  1	import * as _ from 'lodash-es';
  2	import * as React from 'react';
  3	import classNames from 'classnames';
  4	import * as PropTypes from 'prop-types';
  5	import { useTranslation, withTranslation } from 'react-i18next';
  6	import { Divider } from '@patternfly/react-core';
  7	import { CaretDownIcon } from '@patternfly/react-icons/dist/esm/icons/caret-down-icon';
  8	import { CheckIcon } from '@patternfly/react-icons/dist/esm/icons/check-icon';
  9	import { StarIcon } from '@patternfly/react-icons/dist/esm/icons/star-icon';
 10	import { ResourceName } from './ResourceName';
