 12	class DropdownMixin extends React.PureComponent {
 13	  constructor(props) {
 14	    super(props);
 15	    this.listener = this._onWindowClick.bind(this);
 16	    this.state = { active: !!props.active, selectedKey: props.selectedKey };
 17	    this.toggle = this.toggle.bind(this);
 18	    this.dropdownElement = React.createRef();
 19	    this.dropdownList = React.createRef();
 20	  }
 21	
 22	  _onWindowClick(event) {
 23	    if (!this.state.active) {
 24	      return;
 25	    }
 26	
 27	    const { current } = this.dropdownElement;
 28	    if (!current) {
 29	      return;
 30	    }
 31	
 32	    if (
 33	      event.target === current ||
 34	      (current && current.contains(event.target))
 35	    ) {
 36	      return;
 37	    }
 38	
 39	    this.hide(event);
 40	  }
 41	
 42	  UNSAFE_componentWillReceiveProps({ selectedKey, items }) {
 43	    if (selectedKey !== this.props.selectedKey) {
 44	      const title = items[selectedKey] || this.props.title;
 45	      this.setState({ selectedKey, title });
 46	    }
 47	  }
 48	
 49	  componentWillUnmount() {
 50	    window.removeEventListener('click', this.listener);
 51	  }
 52	
 53	  onClick_(selectedKey, e) {
 54	    e.preventDefault();
 55	    e.stopPropagation();
 56	    e.nativeEvent?.stopImmediatePropagation?.();
 57	
 58	    const { items, actionItems, onChange, noSelection, title } = this.props;
 59	
 60	    if (onChange) {
 61	      onChange(selectedKey, e);
 62	    }
 63	
 64	    const newTitle = items[selectedKey];
 65	
 66	    if (!actionItems || !_.some(actionItems, { actionKey: selectedKey })) {
 67	      this.setState({
 68	        selectedKey,
 69	        title: noSelection ? title : newTitle,
 70	      });
 71	    }
 72	
 73	    this.hide();
 74	  }
 75	
 76	  toggle(e) {
 77	    e.preventDefault();
 78	
 79	    if (this.props.disabled) {
 80	      return;
 81	    }
 82	
 83	    if (this.state.active) {
 84	      this.hide(e);
 85	    } else {
 86	      this.show(e);
 87	    }
 88	  }
 89	
 90	  show() {
 91	    /* If you're wondering why this isn't in componentDidMount, it's because
 92	     * kebabs are dropdowns. A list of 200 pods would mean 200 global event
 93	     * listeners. This is bad for performance. - ggreer
 94	     */
 95	    window.removeEventListener('click', this.listener);
 96	    window.addEventListener('click', this.listener);
 97	    this.setState({ active: true });
 98	  }
 99	
100	  hide(e) {
101	    e && e.stopPropagation();
102	    window.removeEventListener('click', this.listener);
103	    this.setState({ active: false });
104	  }
105	}
