107	class DropDownRowWithTranslation extends React.PureComponent {
108	  render() {
109	    const {
110	      itemKey,
111	      content,
112	      onclick,
113	      className,
114	      selected,
115	      hover,
116	      autocompleteFilter,
117	      isBookmarked,
118	      onBookmark,
119	      favoriteKey,
120	      canFavorite,
121	      onFavorite,
122	      t,
123	    } = this.props;
124	
125	    let prefix;
126	    const contentString = _.isString(content) ? content : '';
127	
128	    if (!autocompleteFilter && !onBookmark) {
129	      //use pf4 markup if not using the autocomplete dropdown
130	      return (
131	        <li key={itemKey}>
132	          <button
133	            className="pf-v5-c-dropdown__menu-item"
134	            id={`${itemKey}-link`}
135	            data-test-id="dropdown-menu"
136	            data-test-dropdown-menu={itemKey}
137	            onClick={(e) => onclick(itemKey, e)}
138	          >
139	            {content}
140	          </button>
141	        </li>
142	      );
143	    }
144	    if (onBookmark) {
145	      prefix = (
146	        <a
147	          href="#"
148	          className={classNames(
149	            'pf-v6-c-menu__item-action pf-m-favorite',
150	            { hover, focus: selected },
151	            { 'pf-m-favorited': isBookmarked },
152	          )}
153	          onClick={(e) => {
154	            e.preventDefault();
155	            e.stopPropagation();
156	            onBookmark(itemKey, !isBookmarked);
157	          }}
158	          aria-label={
159	            isBookmarked
160	              ? t(
161	                  'plugin__pipelines-console-plugin~Remove bookmark {{content}}',
162	                  {
163	                    content: contentString,
164	                  },
165	                )
166	              : t('plugin__pipelines-console-plugin~Add bookmark {{content}}', {
167	                  content: contentString,
168	                })
169	          }
170	        >
171	          <span className="pf-v6-c-menu__item-action-icon">
172	            <StarIcon />
173	          </span>
174	        </a>
175	      );
176	    }
177	
178	    let suffix;
179	    if (isBookmarked && canFavorite) {
180	      const isFavorite = favoriteKey === itemKey;
181	      suffix = (
182	        <a
183	          href="#"
184	          className={classNames('bookmarker', { hover, focus: selected })}
185	          onClick={(e) => {
186	            e.preventDefault();
187	            e.stopPropagation();
188	            onFavorite(isFavorite ? null : itemKey);
189	          }}
190	          aria-label={
191	            isFavorite
192	              ? t(
193	                  'plugin__pipelines-console-plugin~Remove favorite {{content}}',
194	                  {
195	                    content: contentString,
196	                  },
197	                )
198	              : t('plugin__pipelines-console-plugin~Add favorite {{content}}', {
199	                  content: contentString,
200	                })
201	          }
202	        >
203	          <StarIcon className={classNames({ favorite: isFavorite })} />
204	        </a>
205	      );
206	    }
207	
208	    return (
209	      <li
210	        role="option"
211	        className={classNames('pf-v6-c-menu__list-item', className)}
212	        key={itemKey}
213	      >
214	        <a
215	          href="#"
216	          ref={this.link}
217	          id={`${itemKey}-link`}
218	          data-test="dropdown-menu-item-link"
219	          className={classNames('pf-v6-c-menu__item', {
220	            'pf-m-selected': selected,
221	          })}
222	          onClick={(e) => onclick(itemKey, e)}
223	        >
224	          <span className="pf-v6-c-menu__item-main">
225	            <span className="pf-v6-c-menu__item-text">{content}</span>
226	            <span className="pf-v6-c-menu__item-select-icon">
227	              <CheckIcon />
228	            </span>
229	          </span>
230	        </a>
231	        {prefix}
232	        {suffix}
233	      </li>
234	    );
235	  }
236	}
