240	class Dropdown_ extends DropdownMixin {
241	  constructor(props) {
242	    super(props);
243	    this.onClick = (...args) => this.onClick_(...args);
244	
245	    this.state.items = props.items;
246	    this.state.title = props.noSelection
247	      ? props.title
248	      : _.get(props.items, props.selectedKey, props.title);
249	
250	    this.onKeyDown = (e) => this.onKeyDown_(e);
251	    this.changeTextFilter = (e) =>
252	      this.applyTextFilter_(e.target.value, this.props.items);
253	    const { shortCut } = this.props;
254	
255	    this.globalKeyDown = (e) => {
256	      if (e.key === 'Escape' && this.state.active) {
257	        this.hide(e);
258	        return;
259	      }
260	
261	      const { nodeName } = e.target;
262	
263	      if (nodeName === 'INPUT' || nodeName === 'TEXTAREA') {
264	        return;
265	      }
266	
267	      if (!shortCut || e.key !== shortCut) {
268	        return;
269	      }
270	
271	      if (e.ctrlKey || e.altKey || e.metaKey || e.shiftKey) {
272	        return;
273	      }
274	
275	      e.stopPropagation();
276	      e.preventDefault();
277	      this.show(e);
278	    };
279	  }
280	
281	  componentDidMount() {
282	    if (this.props.shortCut) {
283	      window.addEventListener('keydown', this.globalKeyDown);
284	    }
285	  }
286	
287	  componentWillUnmount() {
288	    super.componentWillUnmount();
289	    window.removeEventListener('keydown', this.globalKeyDown);
290	  }
291	
292	  UNSAFE_componentWillReceiveProps(nextProps) {
293	    super.UNSAFE_componentWillReceiveProps(nextProps);
294	    const props = this.props;
295	
296	    if (
297	      _.isEqual(nextProps.items, props.items) &&
298	      nextProps.title === props.title
299	    ) {
300	      return;
301	    }
302	    const title = nextProps.title || props.title;
303	    this.setState({ title });
304	
305	    this.applyTextFilter_(this.state.autocompleteText, nextProps.items);
306	  }
307	
308	  componentDidUpdate(prevProps, prevState) {
309	    if (!prevState.active && this.state.active && this.input) {
310	      // Clear any previous filter when reopening the dropdown.
311	      this.applyTextFilter_('', this.props.items);
312	    }
313	  }
314	
315	  applyTextFilter_(autocompleteText, items) {
316	    const { autocompleteFilter } = this.props;
317	    if (autocompleteFilter && !_.isEmpty(autocompleteText)) {
318	      items = _.pickBy(items, (item, key) =>
319	        autocompleteFilter(autocompleteText, item, key),
320	      );
321	    }
322	    this.setState({ autocompleteText, items });
323	  }
324	
325	  onKeyDown_(e) {
326	    const { key } = e;
327	
328	    if (key !== 'ArrowDown' && key !== 'ArrowUp' && key !== 'Enter') {
329	      return;
330	    }
331	
332	    const { keyboardHoverKey } = this.state;
333	    const { items } = this.props;
334	
335	    if (key === 'Enter') {
336	      if (this.state.active && items[keyboardHoverKey]) {
337	        this.onClick(keyboardHoverKey, e);
338	      }
339	      return;
340	    }
341	
342	    const keys = _.keys(items);
343	
344	    let index = _.indexOf(keys, keyboardHoverKey);
345	
346	    if (key === 'ArrowDown') {
347	      index += 1;
348	    } else {
349	      index -= 1;
350	    }
351	
352	    // periodic boundaries
353	    if (index >= keys.length) {
354	      index = 0;
355	    }
356	    if (index < 0) {
357	      index = keys.length - 1;
358	    }
359	
360	    const newKey = keys[index];
361	    this.setState({ keyboardHoverKey: newKey });
362	    e.stopPropagation();
363	  }
364	
365	  renderActionItem() {
366	    const { actionItems } = this.props;
367	    if (actionItems) {
368	      const { selectedKey, keyboardHoverKey, noSelection } = this.props;
369	      return (
370	        <>
371	          {actionItems.map((ai) => (
372	            <DropDownRow
373	              className={classNames({
374	                active: ai.actionKey === selectedKey && !noSelection,
375	              })}
376	              key={`${ai.actionKey}-${ai.actionTitle}`}
377	              itemKey={ai.actionKey}
378	              content={ai.actionTitle}
379	              onclick={this.onClick}
380	              selected={ai.actionKey === selectedKey && !noSelection}
381	              hover={ai.actionKey === keyboardHoverKey}
382	            />
383	          ))}
384	          <Divider component="li" />
385	        </>
386	      );
387	    }
388	    return null;
389	  }
390	
391	  render() {
392	    const {
393	      active,
394	      autocompleteText,
395	      selectedKey,
396	      items,
397	      title,
398	      keyboardHoverKey,
399	    } = this.state;
400	    const {
401	      ariaLabel,
402	      autocompleteFilter,
403	      autocompletePlaceholder,
404	      className,
405	      buttonClassName,
406	      menuClassName,
407	      storageKey,
408	      dropDownClassName,
409	      dropDownContentClassName,
410	      titlePrefix,
411	      describedBy,
412	      disabled,
413	      bookmarks,
414	      onBookmark,
415	      favoriteKey,
416	      canFavorite,
417	      onFavorite,
418	    } = this.props;
419	    const spacerBefore = this.props.spacerBefore || new Set();
420	    const headerBefore = this.props.headerBefore || {};
421	    const rows = [];
422	    const bookMarkRows = [];
423	
424	    const addItem = (key, content) => {
425	      const selected = key === selectedKey && !this.props.noSelection;
426	      const hover = key === keyboardHoverKey;
427	      const klass = classNames({ active: selected });
428	      if (storageKey && bookmarks && bookmarks[key]) {
429	        bookMarkRows.push(
430	          <DropDownRow
431	            className={klass}
432	            key={key}
433	            itemKey={key}
434	            content={content}
435	            onclick={this.onClick}
436	            selected={selected}
437	            hover={hover}
438	            isBookmarked
439	            onBookmark={onBookmark}
440	            favoriteKey={favoriteKey}
441	            canFavorite={canFavorite}
442	            onFavorite={onFavorite}
443	          />,
444	        );
445	        return;
446	      }
447	      if (spacerBefore.has(key)) {
448	        rows.push(
449	          <li key={`${key}-spacer`}>
450	            <div className="dropdown-menu__divider" />
451	          </li>,
452	        );
453	      }
454	
455	      if (_.has(headerBefore, key)) {
456	        rows.push(
457	          <li key={`${key}-header`}>
458	            <div className="dropdown-menu__header">{headerBefore[key]}</div>
459	          </li>,
460	        );
461	      }
462	      rows.push(
463	        <DropDownRow
464	          className={klass}
465	          key={key}
466	          itemKey={key}
467	          content={content}
468	          onBookmark={storageKey && onBookmark}
469	          onclick={this.onClick}
470	          selected={selected}
471	          hover={hover}
472	          autocompleteFilter={autocompleteFilter}
473	        />,
474	      );
475	    };
476	
477	    _.each(items, (v, k) => addItem(k, v));
478	    //render PF4 dropdown markup if this is not the autocomplete filter
479	    if (autocompleteFilter) {
480	      return (
481	        <div
482	          className={className}
483	          ref={this.dropdownElement}
484	          style={this.props.style}
485	        >
486	          <div
487	            className={classNames(
488	              'pf-v5-c-dropdown',
489	              { 'pf-m-expanded': this.state.active },
490	              dropDownClassName,
491	            )}
492	          >
493	            <button
494	              aria-label={ariaLabel}
495	              aria-haspopup="true"
496	              onClick={this.toggle}
497	              onKeyDown={this.onKeyDown}
498	              type="button"
499	              className={classNames(
500	                'pf-v5-c-dropdown__toggle',
501	                buttonClassName,
502	              )}
503	              id={this.props.id}
504	              aria-describedby={describedBy}
505	              disabled={disabled}
506	              data-test={this.props.dataTest}
507	            >
508	              <div
509	                className={classNames(
510	                  'pf-v5-c-dropdown__content-wrap',
511	                  dropDownContentClassName,
512	                )}
513	              >
514	                <span className="pf-v5-c-dropdown__toggle-text">
515	                  {titlePrefix && `${titlePrefix}: `}
516	                  {title}
517	                </span>
518	                <CaretDownIcon className="pf-c-dropdown__toggle-icon" />
519	              </div>
520	            </button>
521	            {active && (
522	              // Style the Application menu to match the Project selection menu
523	              <div className="pf-v6-c-menu pf-m-scrollable co-namespace-dropdown__menu">
524	                <div
525	                  className="pf-v6-c-menu__content"
526	                  style={{ maxHeight: '60vh' }}
527	                >
528	                  {autocompleteFilter && (
529	                    <>
530	                      <div className="pf-v6-c-menu__search">
531	                        <input
532	                          autoFocus
533	                          type="text"
534	                          ref={(input) => (this.input = input)}
535	                          onChange={this.changeTextFilter}
536	                          placeholder={autocompletePlaceholder}
537	                          value={autocompleteText || ''}
538	                          autoCapitalize="none"
539	                          onKeyDown={this.onKeyDown}
540	                          className="pf-v6-c-form-control pf-m-search"
541	                          onClick={(e) => e.stopPropagation()}
542	                          data-test-id="dropdown-text-filter"
543	                        />
544	                      </div>
545	                      <Divider />
546	                    </>
547	                  )}
548	                  {_.size(bookMarkRows) ? (
549	                    <h1 className="pf-v6-c-menu__group-title">Favorites</h1>
550	                  ) : null}
551	                  <ul
552	                    role="listbox"
553	                    ref={this.dropdownList}
554	                    className="pf-v6-c-menu__list dropdown-menu__autocomplete-filter"
555	                  >
556	                    {this.renderActionItem()}
557	                    {bookMarkRows}
558	                    {_.size(bookMarkRows) && _.size(rows) ? (
559	                      <Divider component="li" />
560	                    ) : null}
561	                    {rows}
562	                  </ul>
563	                </div>
564	              </div>
565	            )}
566	          </div>
567	        </div>
568	      );
569	    }
570	
571	    //pf4 markup
572	    return (
573	      <div
574	        className={className}
575	        ref={this.dropdownElement}
576	        style={this.props.style}
577	      >
578	        <div
579	          className={classNames(
580	            { 'pf-v5-c-dropdown': true, 'pf-m-expanded': this.state.active },
581	            dropDownClassName,
582	          )}
583	        >
584	          <button
585	            aria-label={ariaLabel}
586	            aria-haspopup="true"
587	            aria-expanded={this.state.active}
588	            className={classNames('pf-v5-c-dropdown__toggle', buttonClassName)}
589	            data-test-id="dropdown-button"
590	            onClick={this.toggle}
591	            onKeyDown={this.onKeyDown}
592	            type="button"
593	            id={this.props.id}
594	            data-test={this.props.dataTest}
595	            aria-describedby={describedBy}
596	            disabled={disabled}
597	          >
598	            <span className="pf-v5-c-dropdown__toggle-text">
599	              {titlePrefix && `${titlePrefix}: `}
600	              {title}
601	            </span>
602	            <CaretDownIcon className="pf-c-dropdown__toggle-icon" />
603	          </button>
604	          {active && (
605	            <ul
606	              ref={this.dropdownList}
607	              className={classNames('pf-v5-c-dropdown__menu', menuClassName)}
608	            >
609	              {rows}
610	            </ul>
611	          )}
612	        </div>
613	      </div>
614	    );
615	  }
616	}
617	
618	export const Dropdown = (props) => {
619	  return <Dropdown_ {...props} />;
620	};
621	
622	Dropdown.displayName = 'Dropdown';
623	
624	Dropdown.propTypes = {
625	  actionItems: PropTypes.arrayOf(
626	    PropTypes.shape({
627	      actionKey: PropTypes.string,
628	      actionTitle: PropTypes.string,
629	    }),
630	  ),
631	  autocompleteFilter: PropTypes.func,
632	  autocompletePlaceholder: PropTypes.string,
633	  canFavorite: PropTypes.bool,
634	  className: PropTypes.string,
635	  dropDownClassName: PropTypes.string,
636	  dropDownContentClassName: PropTypes.string,
637	  enableBookmarks: PropTypes.bool,
638	  headerBefore: PropTypes.objectOf(PropTypes.string),
639	  items: PropTypes.object.isRequired,
640	  menuClassName: PropTypes.string,
641	  buttonClassName: PropTypes.string,
642	  noSelection: PropTypes.bool,
643	  userSettingsPrefix: PropTypes.string,
644	  storageKey: PropTypes.string,
645	  spacerBefore: PropTypes.instanceOf(Set),
646	  textFilter: PropTypes.string,
647	  title: React.ReactNode,
648	  disabled: PropTypes.bool,
649	  id: PropTypes.string,
650	  onChange: PropTypes.func,
651	  selectedKey: PropTypes.string,
652	  titlePrefix: PropTypes.string,
653	  ariaLabel: PropTypes.string,
654	  name: PropTypes.string,
655	  autoSelect: PropTypes.bool,
656	  describedBy: PropTypes.string,
657	  required: PropTypes.bool,
658	  dataTest: PropTypes.string,
659	};
660	
661	const containerLabel = (container) => (
662	  <ResourceName name={container ? container.name : ''} kind="Container" />
663	);
664	
665	export const ContainerDropdown = (props) => {
666	  const { t } = useTranslation('plugin__pipelines-console-plugin');
667	
668	  const getSpacer = (container) => {
669	    const spacerBefore = new Set();
670	    return container ? spacerBefore.add(container.name) : spacerBefore;
671	  };
672	
673	  const getHeaders = (container, initContainer) => {
674	    return initContainer
675	      ? {
676	          [container.name]: t('plugin__pipelines-console-plugin~Containers'),
677	          [initContainer.name]: t(
678	            'plugin__pipelines-console-plugin~Init containers',
679	          ),
680	        }
681	      : {};
682	  };
683	
684	  const { currentKey, containers, initContainers, onChange } = props;
685	  if (_.isEmpty(containers) && _.isEmpty(initContainers)) {
686	    return null;
687	  }
688	  const firstInitContainer = _.find(initContainers, { order: 0 });
689	  const firstContainer = _.find(containers, { order: 0 });
690	  const spacerBefore = getSpacer(firstInitContainer);
691	  const headerBefore = getHeaders(firstContainer, firstInitContainer);
692	  const dropdownItems = _.mapValues(
693	    _.merge(containers, initContainers),
694	    containerLabel,
695	  );
696	  const title =
697	    _.get(dropdownItems, currentKey) || containerLabel(firstContainer);
698	  return (
699	    <Dropdown
700	      headerBefore={headerBefore}
701	      items={dropdownItems}
702	      spacerBefore={spacerBefore}
703	      title={title}
704	      onChange={onChange}
705	      selectedKey={currentKey}
706	    />
707	  );
708	};
709	
710	ContainerDropdown.propTypes = {
711	  containers: PropTypes.oneOfType([PropTypes.object, PropTypes.array])
712	    .isRequired,
713	  currentKey: PropTypes.oneOfType([PropTypes.string, PropTypes.number]),
714	  initContainers: PropTypes.object,
715	  onChange: PropTypes.func.isRequired,
716	};
717	
718	ContainerDropdown.defaultProps = {
719	  currentKey: '',
720	  initContainers: {},
721	};

