240	class Dropdown_ extends DropdownMixin {
241	  constructor(props) {
242	    super(props);
243	    this.onClick = (...args) => this.onClick_(...args);
244	
245	    this.state.items = props.items;
246	    this.state.title = props.noSelection
247	      ? props.title
248	      : _.get(props.items, props.selectedKey, props.title);
249	
250	    this.onKeyDown = (e) => this.onKeyDown_(e);
251	    this.changeTextFilter = (e) =>
252	      this.applyTextFilter_(e.target.value, this.props.items);
253	    const { shortCut } = this.props;
254	
255	    this.globalKeyDown = (e) => {
256	      if (e.key === 'Escape' && this.state.active) {
257	        this.hide(e);
258	        return;
259	      }
260	
261	      const { nodeName } = e.target;
262	
263	      if (nodeName === 'INPUT' || nodeName === 'TEXTAREA') {
264	        return;
265	      }
266	
267	      if (!shortCut || e.key !== shortCut) {
268	        return;
269	      }
270	
271	      if (e.ctrlKey || e.altKey || e.metaKey || e.shiftKey) {
272	        return;
273	      }
274	
275	      e.stopPropagation();
276	      e.preventDefault();
277	      this.show(e);
278	    };
279	  }
