667	
668	  const getSpacer = (container) => {
669	    const spacerBefore = new Set();
670	    return container ? spacerBefore.add(container.name) : spacerBefore;
671	  };
672	
673	  const getHeaders = (container, initContainer) => {
674	    return initContainer
675	      ? {
676	          [container.name]: t('plugin__pipelines-console-plugin~Containers'),
677	          [initContainer.name]: t(
678	            'plugin__pipelines-console-plugin~Init containers',
679	          ),
