689	  const firstContainer = _.find(containers, { order: 0 });
690	  const spacerBefore = getSpacer(firstInitContainer);
691	  const headerBefore = getHeaders(firstContainer, firstInitContainer);
692	  const dropdownItems = _.mapValues(
693	    _.merge(containers, initContainers),
694	    containerLabel,
695	  );
696	  const title =
697	    _.get(dropdownItems, currentKey) || containerLabel(firstContainer);
698	  return (
699	    <Dropdown
700	      headerBefore={headerBefore}
701	      items={dropdownItems}
702	      spacerBefore={spacerBefore}
703	      title={title}
704	      onChange={onChange}
