559	                      <Divider component="li" />
560	                    ) : null}
561	                    {rows}
562	                  </ul>
563	                </div>
564	              </div>
565	            )}
566	          </div>
567	        </div>
568	      );
569	    }
570	
571	    //pf4 markup
572	    return (
573	      <div
574	        className={className}
575	        ref={this.dropdownElement}
576	        style={this.props.style}
577	      >
578	        <div
579	          className={classNames(
580	            { 'pf-v6-c-menu': true, 'pf-m-expanded': this.state.active },
581	            dropDownClassName,
582	          )}
583	        >
584	          <button
